-- 13. Nissan GT-R R35 (2009) (car_id=121, bq_id=171)
-- body=85, nvh=72, int=78, paint=80, elc_age=70, cosmetic=75 => 21.25+7.2+15.6+12+10.5+11.25=77.8
INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (171, 121, 77.8, 85, 72, 78, 80, 70, 75, 'Premium Midship platform - carbon fiber composite driveshaft tunnel, aluminum hood/fenders, excellent rigidity', 'GT-R is surprisingly refined when cruising - V6 is smooth, road noise is well-damped for the performance level', 'Early R35 interior was good for 2009 - Premium trim gets leather, later models improve significantly', 'Nissan paint quality on GT-R is a step above standard - special colors like Vibrant Red are deep and rich', 'Complex performance electronics - multi-function display, ATTESA controllers, but generally well-engineered', 'Interior materials age well in Premium trim - NISMO edition gets Alcantara and carbon fiber', 'Supercar build quality in a Nissan body - the Premium Midship platform is genuinely impressive engineering', 'Nissan PM platform (Premium Midship)', 'Nissan Tochigi (Japan - Takumi craftsmen)', 'spot weld + structural adhesive + laser weld + carbon fiber bonding', 3.0, 'solid hydraulic', 'acoustic laminated', 'premium leather', 'carbon fiber trim', 7, 'good', 'sample');

