INSERT INTO build_quality (id, car_id, q_score, score_body_construction, score_nvh_isolation, score_interior_materials, score_paint_corrosion, score_electrical_aging, score_cosmetic_aging, body_construction_notes, nvh_isolation_notes, interior_materials_notes, paint_corrosion_notes, electrical_aging_notes, cosmetic_aging_notes, q_score_notes, platform_type, assembly_plant, weld_technology, panel_gap_mm, engine_mount_type, glass_type, leather_grade, wood_type, paint_stages, sound_deadening_rating, source) VALUES (172, 131, 70.5, 72, 65, 70, 70, 73, 70, 'Toyota/Subaru jointly developed platform - good rigidity for a lightweight RWD coupe, low center of gravity', 'Sports car NVH - tire noise and engine note are prominent, acceptable for the class, wind noise at speed', 'Better than expected for the price - Toyota influence on interior quality is evident, simple but well-assembled', 'Standard Subaru paint - adequate but thin, stone chips on front bumper and hood are common', 'Simple modern electronics - Pioneer head unit (2017) is dated but functional, few electronic issues', 'Interior materials hold up well for a $25k sports car - steering wheel and seats age gracefully', 'Joint Toyota-Subaru development shows - better build quality than pure Subaru products of the same era', 'Toyota/Toyota 86 platform (joint development)', 'Subaru Gunma Yajima (Japan)', 'spot weld + structural adhesive', 4.0, 'hydraulic', 'tinted', 'available leather/alcantara', 'none', 5, 'below_average', 'sample');
